var __index = {"config":{"lang":["en"],"separator":"[\\s\\-]+","pipeline":[" "],"fields":{"title":{"boost":1000.0},"text":{"boost":1.0},"tags":{"boost":1000000.0}}},"docs":[{"location":"index.html","title":"OpenClaw \u2014 Local AI Agent Orchestration with MCP","text":"<p>OpenClaw\uc740 MCP(Model Context Protocol)\ub97c \ud1b5\ud574 \uc5ec\ub7ec AI Agent(Codex, Claude, Ollama)\ub97c \uc870\uc728\ud558\ub294 \ub85c\uceec \uba40\ud2f0 Agent \uc2dc\uc2a4\ud15c\uc785\ub2c8\ub2e4.</p>"},{"location":"index.html#project-goals","title":"Project Goals","text":"<ul> <li>\uc791\uc5c5 \uc720\ud615\uacfc \ub9e5\ub77d\uc5d0 \ub530\ub77c \ucd5c\uc801\uc758 Agent\ub85c \ub77c\uc6b0\ud305   </li> <li>MCP Tool\uc744 \ud1b5\ud574 Agent \uac04 \ud1b5\uc2e0 \ubc0f \uc791\uc5c5 \uc778\uacc4   </li> <li>\uac00\ub2a5\ud55c \ud55c \ub85c\uceec\uc5d0\uc11c \uc2e4\ud589 (Ollama), \ud074\ub77c\uc6b0\ub4dc Fallback (Claude, Codex)   </li> <li>\uc7ac\ud604\uc131\uacfc \ubd84\uc11d\uc744 \uc704\ud574 \ubaa8\ub4e0 \uc2e4\ud589 \ub85c\uadf8 \uae30\ub85d</li> </ul>"},{"location":"index.html#quick-start","title":"Quick Start","text":"<ol> <li>Ollama \uc124\uce58 (Windows) \u2192 agents/ollama_setup.md </li> <li>OpenClaw \uc124\uce58 (WSL2) \u2192 environments/window_wsl2_setup.md </li> <li>MCP \uc11c\ubc84 \uc2dc\uc791 \u2192 mcp/mcp_server.md </li> <li>Agent \uc124\uc815 \u2192 agents/ </li> <li>\uc2e4\ud5d8 \uc2e4\ud589 \u2192 experiments/openclaw_test.md</li> </ol>"},{"location":"index.html#manual","title":"Manual","text":""},{"location":"index.html#architecture","title":"Architecture","text":"\ubb38\uc11c \uc124\uba85 System Design Agent \ud1a0\ud3f4\ub85c\uc9c0, \ub77c\uc6b0\ud305 \ub85c\uc9c1, MCP \ud750\ub984"},{"location":"index.html#agents","title":"Agents","text":"\ubb38\uc11c \uc124\uba85 Claude \ucd94\ub860\u00b7\ubd84\uc11d, Anthropic API Claude Setup \uc778\uc99d, Windows \ub514\ub809\ud1a0\ub9ac \uad6c\uc870 Claude MCP MCP Tool Signature Codex \ucf54\ub4dc \uc0dd\uc131, OpenAI API Ollama \ub85c\uceec \ucd94\ub860, API \ud0a4 \ubd88\ud544\uc694 Ollama Setup Windows \uc124\uce58 \ubc0f WSL2 \uc5f0\uacb0"},{"location":"index.html#mcp","title":"MCP","text":"\ubb38\uc11c \uc124\uba85 MCP Server \uc11c\ubc84 \uc124\uc815, Tool \uc815\uc758, Protocol Flow"},{"location":"index.html#environments","title":"Environments","text":"\ubb38\uc11c \uc124\uba85 Windows WSL2 Setup WSL2\uc5d0\uc11c OpenClaw \uc124\uce58 \uc804\uccb4 \uc808\ucc28"},{"location":"index.html#experiments","title":"Experiments","text":"\ubb38\uc11c \uc124\uba85 OpenClaw Test Agent \ub77c\uc6b0\ud305 \uac80\uc99d \ud14c\uc2a4\ud2b8"},{"location":"index.html#logs","title":"Logs","text":"\ubb38\uc11c \uc124\uba85 run_001 \uccab \ubc88\uc9f8 \uc2e4\ud589 \ub85c\uadf8"},{"location":"index.html#status","title":"Status","text":"<p>\uc124\uce58 \uc9c4\ud589 \uc911 \u2014 Ollama (Windows) + OpenClaw (WSL2)</p>"},{"location":"agents/claude.html","title":"Agent: Claude","text":""},{"location":"agents/claude.html#purpose","title":"Purpose","text":"<p>\ucd94\ub860, \ubd84\uc11d, \uc7a5\ubb38 \ucee8\ud14d\uc2a4\ud2b8 \uc774\ud574, \ub2e4\ub2e8\uacc4 \uacc4\ud68d \uc218\ub9bd</p>"},{"location":"agents/claude.html#model","title":"Model","text":"<ul> <li>\uc81c\uacf5\uc790: Anthropic</li> <li>\ubaa8\ub378: <code>claude-sonnet-4-6</code> (\uae30\ubcf8), \ubcf5\uc7a1\ud55c \uc791\uc5c5\uc5d4 <code>claude-opus-4-6</code></li> <li>API: Anthropic Messages API</li> </ul>"},{"location":"agents/claude.html#when-to-use","title":"When to Use","text":"<ul> <li>\ub2e4\ub2e8\uacc4 \ucd94\ub860 \ub610\ub294 \uacc4\ud68d \uc218\ub9bd \uc791\uc5c5</li> <li>\ubb38\uc11c \ubd84\uc11d \ubc0f \uc694\uc57d</li> <li>\ucf54\ub4dc\ub098 \uc544\ud0a4\ud14d\ucc98 \uacb0\uc815 \uc124\uba85</li> <li>\uc138\ubc00\ud55c \ud310\ub2e8\uc774 \ud544\uc694\ud55c \uc791\uc5c5</li> </ul>"},{"location":"agents/claude.html#configuration","title":"Configuration","text":"<pre><code>{\n  \"agent\": \"claude\",\n  \"model\": \"claude-sonnet-4-6\",\n  \"max_tokens\": 4096,\n  \"system_prompt\": \"You are a helpful assistant with strong reasoning skills.\"\n}\n</code></pre>"},{"location":"agents/claude.html#notes","title":"Notes","text":"<ul> <li>\uae4a\uc740 \ucd94\ub860\uc774 \ud544\uc694\ud55c \uc791\uc5c5\uc5d4 <code>claude-opus-4-6</code> \uc0ac\uc6a9 (\ube44\uc6a9 \ub192\uc74c)</li> <li>\ubcf5\uc7a1\ud55c \ub2e4\ub2e8\uacc4 \ubb38\uc81c\uc5d4 extended thinking \ud65c\uc131\ud654</li> <li>\ucf54\ub4dc \uc774\ud574 + \uc124\uba85\uc774 \uacb0\ud569\ub41c \uc791\uc5c5\uc5d0 \uac00\uc7a5 \uc801\ud569\ud55c Agent</li> </ul>"},{"location":"agents/claude.html#related","title":"Related","text":"<ul> <li>claude_setup.md \u2014 \uc778\uc99d \ubc0f Windows \uc124\uc815</li> <li>claude_mcp.md \u2014 MCP Tool Signature</li> </ul>"},{"location":"agents/claude_mcp.html","title":"Agent: Claude \u2014 MCP","text":""},{"location":"agents/claude_mcp.html#mcp-tool-signature","title":"MCP Tool Signature","text":"<pre><code>claude.run(prompt: string, context?: string, thinking?: boolean) \u2192 TextResult\n</code></pre>"},{"location":"agents/claude_setup.html","title":"Agent: Claude \u2014 Setup","text":""},{"location":"agents/claude_setup.html#1-claude-rule-files","title":"1. Claude Rule Files","text":"<p>Claude\uac00 \uc774 \ud504\ub85c\uc81d\ud2b8\uc5d0\uc11c \uc791\uc5c5\ud560 \ub54c \ucc38\uc870\ud558\ub294 \uaddc\uce59 \ud30c\uc77c\ub4e4\uc758 \uc704\uce58\uc640 \uc5ed\ud560.</p>"},{"location":"agents/claude_setup.html#project-root","title":"Project Root","text":"<p>\ubaa8\ub4e0 \uaddc\uce59\uc740 <code>claude.md</code> \ud558\ub098\ub85c \ud1b5\ud569\ub418\uc5b4 \uc788\ub2e4.  <code>context.md</code>, <code>skill/</code> \ub514\ub809\ud1a0\ub9ac\ub294 \uc0ad\uc81c\ub418\uc5c8\ub2e4.</p> \ud30c\uc77c \uc5ed\ud560 <code>claude.md</code> \ubaa8\ub4e0 \ud589\ub3d9 \uaddc\uce59 \u2014 AI Agent Workflow, \ud658\uacbd, \ud30c\uc77c \uc870\uc791, \ubb38\uc11c, \uc124\uce58, \ucee8\ud14d\uc2a4\ud2b8, \uba54\ubaa8\ub9ac \uaddc\uce59"},{"location":"agents/claude_setup.html#user-memory","title":"User Memory","text":"<p>\uc138\uc158 \uac04 \uae30\uc5b5\uc774 \ud544\uc694\ud55c \uacb0\uc815\uc0ac\ud56d\uc744 \uc800\uc7a5\ud558\ub294 \ub514\ub809\ud1a0\ub9ac\uc774\ub2e4.  Claude Code\uac00 \ub300\ud654 \uc2dc\uc791 \uc2dc \uc790\ub3d9\uc73c\ub85c \ub85c\ub4dc\ud55c\ub2e4.</p> <pre><code>C:\\Users\\&lt;user&gt;\\.claude\\projects\\d--works-projects-local-ai-agent-mcp\\memory\n</code></pre> \ud30c\uc77c \uc5ed\ud560 <code>MEMORY.md</code> \uba54\ubaa8\ub9ac \ud30c\uc77c \uc778\ub371\uc2a4 \u2014 \ud56d\uc0c1 \ucee8\ud14d\uc2a4\ud2b8\uc5d0 \ub85c\ub4dc\ub428 <code>project_overview.md</code> \ud504\ub85c\uc81d\ud2b8 \ubaa9\uc801, \ud575\uc2ec \ucef4\ud3ec\ub10c\ud2b8, \uc8fc\uc694 \ubb38\uc11c \uc704\uce58"},{"location":"agents/claude_setup.html#claude-context-loading-order","title":"Claude Context Loading Order","text":"<pre><code>1. claude.md                        (\ubaa8\ub4e0 \uaddc\uce59)\n2. \uc791\uc5c5 \uad00\ub828 docs/ \ubb38\uc11c             (\ud544\uc694\ud55c \uac83\ub9cc)\n3. memory/MEMORY.md \u2192 \uac01 memory \ud30c\uc77c (\uc138\uc158 \uac04 \uae30\uc5b5)\n4. \ud604\uc7ac \ub300\ud654 \ud788\uc2a4\ud1a0\ub9ac\n5. \uc0ac\uc6a9\uc790 \uc785\ub825\n</code></pre>"},{"location":"agents/claude_setup.html#2user-claude-enviornment","title":"2.User Claude Enviornment","text":"<p>Claude \uc0ac\uc6a9\uc790\uc758 \ud658\uacbd\uc740 \ub2e4\uc740\uacfc \uac19\uc774 \uad6c\uc131\ub428 </p>"},{"location":"agents/claude_setup.html#window","title":"Window","text":"<p>Claude Code\ub294 Windows\uc5d0\uc11c <code>C:\\Users\\&lt;user&gt;\\.claude\\</code> \uc5d0 \ubaa8\ub4e0 \uc124\uc815\uacfc \ub370\uc774\ud130\ub97c \uc800\uc7a5\ud55c\ub2e4.</p> \uacbd\ub85c \ubaa9\uc801 <code>.credentials</code> <code>claude auth login</code> \uc778\uc99d \ud1a0\ud070. WSL2\ub85c \ubcf5\uc0ac\ud574 \uc7ac\uc0ac\uc6a9 \uac00\ub2a5 <code>config.json</code> Claude Code \uc804\uc5ed \uc124\uc815 <code>settings.json</code> \uad8c\ud55c\u00b7Hook\u00b7MCP \ub4f1 \uc138\ubd80 \uc124\uc815 <code>history.jsonl</code> \ub300\ud654 \ud788\uc2a4\ud1a0\ub9ac <code>sessions/</code> \uc138\uc158\ubcc4 \ucee8\ud14d\uc2a4\ud2b8 \uc800\uc7a5 <code>projects/</code> \ud504\ub85c\uc81d\ud2b8\ubcc4 memory \ubc0f \uc124\uc815 (<code>d--works-projects-*</code> \ud615\uc2dd) <code>plugins/</code> \uc124\uce58\ub41c Plugin \ubaa9\ub85d \ubc0f marketplace \uc815\ubcf4 <code>cache/</code> changelog \ub4f1 \uce90\uc2dc \ud30c\uc77c <code>ide/</code> IDE Extension \uc5f0\uacb0 lock \ud30c\uc77c <code>backups/</code> \uc124\uc815 \ubc31\uc5c5 <code>debug/</code> \ub514\ubc84\uadf8 \ub85c\uadf8 <code>shell-snapshots/</code> Shell \uc0c1\ud0dc \uc2a4\ub0c5\uc0f7"},{"location":"agents/claude_setup.html#3claude-authentication","title":"3.Claude Authentication","text":"<p>Claude \ud544\uc694\ud55c \uc778\uc99d </p>"},{"location":"agents/claude_setup.html#method-1-credentials-copy-wsl2","title":"Method 1: Credentials Copy (WSL2 \uad8c\uc7a5)","text":"<p>Windows\uc5d0\uc11c \uc774\ubbf8 <code>claude auth login</code>\uc744 \uc644\ub8cc\ud55c \uacbd\uc6b0 credentials \ud30c\uc77c\uc744 \ubcf5\uc0ac\ud55c\ub2e4.</p> <pre><code># WSL2 \ub0b4\uc5d0\uc11c \uc2e4\ud589\ncp /mnt/c/Users/ahyuo/.claude/.credentials ~/.claude/.credentials\n</code></pre>"},{"location":"agents/claude_setup.html#method-2-interactive-login","title":"Method 2: Interactive Login","text":"<pre><code>claude auth login\n# WSL\uc5d0\uc11c \ube0c\ub77c\uc6b0\uc800\uac00 \uc5f4\ub9ac\uc9c0 \uc54a\uc73c\uba74 \ucd9c\ub825\ub41c URL\uc744 Windows \ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c \uc5f4\uae30\n</code></pre>"},{"location":"agents/claude_setup.html#method-3-api-key-environment-variable","title":"Method 3: API Key Environment Variable","text":"<p>WSL / Linux: <pre><code>echo 'export ANTHROPIC_API_KEY=\"sk-ant-...\"' &gt;&gt; ~/.bashrc\nsource ~/.bashrc\n</code></pre></p> <p>Windows (PowerShell): <pre><code>$env:ANTHROPIC_API_KEY = \"sk-ant-...\"\n</code></pre></p>"},{"location":"agents/claude_setup.html#verify-authentication","title":"Verify Authentication","text":"<pre><code>claude auth status\necho $ANTHROPIC_API_KEY   # API Key \uc124\uc815 \uc5ec\ubd80 \ud655\uc778\nclaude -p \"hello\"          # \ub3d9\uc791 \ud14c\uc2a4\ud2b8\n</code></pre>"},{"location":"agents/codex.html","title":"Agent: Codex","text":""},{"location":"agents/codex.html#purpose","title":"Purpose","text":"<p>\ucf54\ub4dc \uc0dd\uc131, \uc644\uc131, \ubcc0\ud658 \uc791\uc5c5</p>"},{"location":"agents/codex.html#model","title":"Model","text":"<ul> <li>\uc81c\uacf5\uc790: OpenAI</li> <li>\ubaa8\ub378: <code>gpt-4o</code> (\ub808\uac70\uc2dc\ub294 <code>code-davinci-002</code>)</li> <li>API: OpenAI Completions / Chat API</li> </ul>"},{"location":"agents/codex.html#when-to-use","title":"When to Use","text":"<ul> <li>\ubcf4\uc77c\ub7ec\ud50c\ub808\uc774\ud2b8 \ub610\ub294 \uc2a4\uce90\ud3f4\ub529 \uc0dd\uc131</li> <li>\uae30\uc874 \ucf54\ub4dc \ub9ac\ud329\ud1a0\ub9c1</li> <li>\ud568\uc218 \uc2dc\uadf8\ub2c8\ucc98\ub85c\ubd80\ud130 \ub2e8\uc704 \ud14c\uc2a4\ud2b8 \uc791\uc131</li> <li>\uc5b8\uc5b4 \uac04 \ucf54\ub4dc \ubcc0\ud658</li> </ul>"},{"location":"agents/codex.html#configuration","title":"Configuration","text":"<pre><code>{\n  \"agent\": \"codex\",\n  \"model\": \"gpt-4o\",\n  \"temperature\": 0.2,\n  \"max_tokens\": 2048,\n  \"system_prompt\": \"You are an expert software engineer. Output only code unless asked to explain.\"\n}\n</code></pre>"},{"location":"agents/codex.html#mcp-tool-signature","title":"MCP Tool Signature","text":"<pre><code>codex.run(prompt: string, language?: string, context_files?: string[]) \u2192 CodeResult\n</code></pre>"},{"location":"agents/codex.html#notes","title":"Notes","text":"<ul> <li>\uacb0\uc815\ub860\uc801 \ucd9c\ub825\uc744 \uc704\ud574 temperature\ub97c \ub0ae\uac8c \uc720\uc9c0 (0.1\u20130.3)</li> <li>\uc815\ud655\ub3c4 \ud5a5\uc0c1\uc744 \uc704\ud574 <code>context_files</code>\ub85c \uad00\ub828 \ud30c\uc77c \ucee8\ud14d\uc2a4\ud2b8 \uc804\ub2ec</li> <li>\ucd94\ub860 \uc5c6\uc774 \uc21c\uc218 \ucf54\ub4dc \ucd9c\ub825\uc774 \ud544\uc694\ud560 \ub54c Claude \ub300\uc2e0 \uc774 Agent \uc120\ud0dd</li> </ul>"},{"location":"agents/ollama.html","title":"Agent: Ollama","text":""},{"location":"agents/ollama.html#purpose","title":"Purpose","text":"<p>\ub85c\uceec, \uc624\ud504\ub77c\uc778 AI \ucd94\ub860. API \ud0a4 \ubd88\ud544\uc694.</p>"},{"location":"agents/ollama.html#models","title":"Models","text":"\ubaa8\ub378 \uac15\uc810 VRAM \uc774 \ud504\ub85c\uc81d\ud2b8 \uc6a9\ub3c4 <code>llama3.2</code> \uc77c\ubc18 \ucd94\ub860, \uc694\uc57d, \uc790\uc5f0\uc5b4 \uc774\ud574 4 GB \ub85c\uadf8 \uc694\uc57d, \uc774\uc0c1 \ud0d0\uc9c0 <code>mistral</code> \ube60\ub978 \ucc98\ub9ac, \uc9c0\uc2dc \ub530\ub974\uae30 4 GB \ub300\ub7c9 \ub85c\uadf8 \ubd84\uc11d, \ubc18\ubcf5 \ubcc0\ud658 \uc791\uc5c5 <code>codellama</code> \ucf54\ub4dc \uc0dd\uc131, \ucf54\ub4dc \uc124\uba85 4 GB \ud14c\uc2a4\ud2b8 \ucd08\uc548 \uc0dd\uc131, \ub2e8\uc21c \ubcc0\ud658 \uc2a4\ud06c\ub9bd\ud2b8 <code>deepseek-r1</code> \ub2e8\uacc4\uc801 \ucd94\ub860, \uc218\ud559 8 GB+ \ubcf5\uc7a1\ud55c \ub85c\uadf8 \ud328\ud134 \ubd84\uc11d (\uace0\uc0ac\uc591 \ud544\uc694)"},{"location":"agents/ollama.html#model-selection-guide","title":"Model Selection Guide","text":"<p>\ub85c\uadf8 \ubd84\uc11d / \uc694\uc57d</p> <ul> <li>\ub85c\uadf8 \uc591\uc774 \ub9ce\uace0 \ube60\ub978 \ucc98\ub9ac\uac00 \uc6b0\uc120 \u2192 <code>mistral</code></li> <li>\ub9e5\ub77d \uc774\ud574\u00b7\uc774\uc0c1 \ud0d0\uc9c0 \uc815\ud655\ub3c4\uac00 \uc6b0\uc120 \u2192 <code>llama3.2</code></li> <li>\ud328\ud134\uc774 \ubcf5\uc7a1\ud558\uace0 \ucd94\ub860\uc774 \ud544\uc694 \u2192 <code>deepseek-r1</code> (VRAM 8 GB \uc774\uc0c1)</li> </ul> <p>\ud14c\uc2a4\ud2b8 \uc790\ub3d9\ud654</p> <ul> <li>\ud14c\uc2a4\ud2b8 \ucd08\uc548 \ucf54\ub4dc \uc0dd\uc131 \u2192 <code>codellama</code></li> <li>\ub2e8\uc21c \ubc18\ubcf5 \ubcc0\ud658 \uc2a4\ud06c\ub9bd\ud2b8 \u2192 <code>mistral</code></li> <li>\ubcf5\uc7a1\ud55c \ud14c\uc2a4\ud2b8 \ub85c\uc9c1 \uc124\uacc4 \u2192 Claude (Ollama \ubc94\uc704 \uc544\ub2d8)</li> </ul> <p>\uad8c\uc7a5 \uae30\ubcf8 \uad6c\uc131</p> <pre><code>\ub85c\uadf8 \ubd84\uc11d: mistral\n\ud14c\uc2a4\ud2b8 \ucd08\uc548: codellama\n</code></pre>"},{"location":"agents/ollama.html#when-to-use","title":"When to Use","text":"<ul> <li>\uc624\ud504\ub77c\uc778 \ub610\ub294 \ud074\ub77c\uc6b0\ub4dc \uc758\uc874\uc131 \uc5c6\uc774 \uc2e4\ud589\ud574\uc57c \ud558\ub294 \uc791\uc5c5</li> <li>\ub300\uc6a9\ub7c9 / \uc800\ube44\uc6a9 \ucd94\ub860</li> <li>\ud074\ub77c\uc6b0\ub4dc \ubaa8\ub378 \uc804\ud658 \uc804 \ud504\ub85c\ud1a0\ud0c0\uc774\ud551</li> <li>\uac1c\uc778\uc815\ubcf4\uc5d0 \ubbfc\uac10\ud55c \uc785\ub825</li> </ul>"},{"location":"agents/ollama.html#configuration","title":"Configuration","text":"<pre><code>{\n  \"agent\": \"ollama\",\n  \"model\": \"llama3.2\",\n  \"base_url\": \"http://localhost:11434\",\n  \"temperature\": 0.7,\n  \"stream\": false\n}\n</code></pre>"},{"location":"agents/ollama.html#mcp-tool-signature","title":"MCP Tool Signature","text":"<pre><code>ollama.run(prompt: string, model?: string) \u2192 TextResult\n</code></pre>"},{"location":"agents/ollama.html#setup","title":"Setup","text":"<p>Windows</p> <pre><code># \ubc29\ubc95 1: PowerShell \uacf5\uc2dd \uc778\uc2a4\ud1a8\ub7ec (\uad8c\uc7a5)\nirm https://ollama.com/install.ps1 | iex\n</code></pre> <pre><code># \ubc29\ubc95 2: winget\nwinget install Ollama.Ollama\n</code></pre> <pre><code># \ubc29\ubc95 3: https://ollama.com/download \uc5d0\uc11c .exe \uc9c1\uc811 \ub2e4\uc6b4\ub85c\ub4dc\n</code></pre> <pre><code># \ubaa8\ub378 \ub2e4\uc6b4\ub85c\ub4dc\nollama pull llama3.2\n\n# \uc2e4\ud589 \ud655\uc778\nollama list\n</code></pre> <p>Linux / macOS <pre><code># Ollama \uc124\uce58\ncurl -fsSL https://ollama.com/install.sh | sh\n\n# \ubaa8\ub378 \ub2e4\uc6b4\ub85c\ub4dc\nollama pull llama3.2\n\n# \uc2e4\ud589 \ud655\uc778\nollama list\n</code></pre></p>"},{"location":"agents/ollama.html#notes","title":"Notes","text":"<ul> <li>MCP \uc11c\ubc84 \uc2dc\uc791 \uc804\uc5d0 Ollama\uac00 \ub85c\uceec\uc5d0\uc11c \uc2e4\ud589 \uc911\uc774\uc5b4\uc57c \ud568</li> <li>\ud074\ub77c\uc6b0\ub4dc \ubaa8\ub378\ubcf4\ub2e4 \uc751\ub2f5 \ud488\uc9c8\uc774 \ub0ae\uc74c \u2014 \ube60\ub978 \ud544\ud130\ub9c1\uc774\ub098 \ub2e8\uc21c \uc791\uc5c5\uc5d0 \uc0ac\uc6a9</li> <li>\uc2e4\uc2dc\uac04 \ucd9c\ub825\uc774 \ud544\uc694\ud558\uba74 stream \ubaa8\ub4dc \ud65c\uc131\ud654</li> </ul>"},{"location":"agents/ollama_setup.html","title":"Experiment: Ollama Setup on Windows","text":""},{"location":"agents/ollama_setup.html#goal","title":"Goal","text":"<p>Windows 11\uc5d0\uc11c Ollama\ub97c \uc124\uce58\ud558\uace0, WSL2\uc758 OpenClaw\uc640 <code>localhost:11434</code>\ub85c \uc5f0\uacb0\ub418\ub294\uc9c0 \uac80\uc99d\ud569\ub2c8\ub2e4.</p>"},{"location":"agents/ollama_setup.html#environment","title":"Environment","text":"\ud56d\ubaa9 \uac12 OS Windows 11 Pro \uc124\uce58 \ubc29\ubc95 winget \ubc84\uc804 0.20.7"},{"location":"agents/ollama_setup.html#setup-steps","title":"Setup Steps","text":""},{"location":"agents/ollama_setup.html#step-1-install-ollama-on-windows","title":"Step 1: Install Ollama on Windows","text":"<p>\ubc29\ubc95 1 \u2014 PowerShell \uacf5\uc2dd \uc778\uc2a4\ud1a8\ub7ec (\uad8c\uc7a5): <pre><code>irm https://ollama.com/install.ps1 | iex\n</code></pre></p> <p>\ubc29\ubc95 2 \u2014 winget: <pre><code>winget install Ollama.Ollama\n</code></pre></p> <p>\ubc29\ubc95 3 \u2014 \uc9c1\uc811 \ub2e4\uc6b4\ub85c\ub4dc: https://ollama.com/download \uc5d0\uc11c <code>.exe</code> \uc124\uce58</p> <p>\uc124\uce58 \ud6c4 \uc2dc\uc2a4\ud15c \ud2b8\ub808\uc774\uc5d0 Ollama \uc544\uc774\ucf58\uc774 \uc0dd\uae30\uace0 \uc790\ub3d9\uc73c\ub85c \uc11c\ube44\uc2a4\uac00 \uc2dc\uc791\ub429\ub2c8\ub2e4.</p>"},{"location":"agents/ollama_setup.html#step-2-pull-models","title":"Step 2: Pull Models","text":"<pre><code># \uacbd\ub7c9 \ubc94\uc6a9 \ubaa8\ub378 (\uad8c\uc7a5 \uc2dc\uc791\uc810, \uc57d 2GB)\nollama pull llama3.2\n\n# \ucf54\ub4dc \ud2b9\ud654 \ubaa8\ub378 (\uc120\ud0dd)\nollama pull codellama\n\n# \uc124\uce58\ub41c \ubaa8\ub378 \ud655\uc778\nollama list\n</code></pre>"},{"location":"agents/ollama_setup.html#step-3-verify-api","title":"Step 3: Verify API","text":"<pre><code># API \uc751\ub2f5 \ud655\uc778\ncurl http://localhost:11434/api/tags\n</code></pre>"},{"location":"agents/ollama_setup.html#step-4-verify-from-wsl2","title":"Step 4: Verify from WSL2","text":"<p>WSL2 \uc548\uc5d0\uc11c\ub3c4 Windows\uc758 Ollama\uc5d0 \uc811\uadfc \uac00\ub2a5\ud569\ub2c8\ub2e4.</p> <pre><code># WSL2 \ud130\ubbf8\ub110\uc5d0\uc11c\ncurl http://localhost:11434/api/tags\n</code></pre> <p>WSL2\ub294 <code>localhost</code>\ub97c \ud1b5\ud574 Windows \ud638\uc2a4\ud2b8 \ud3ec\ud2b8\uc5d0 \uc790\ub3d9\uc73c\ub85c \uc811\uadfc\ub429\ub2c8\ub2e4.</p>"},{"location":"agents/ollama_setup.html#checklist","title":"Checklist","text":"<ul> <li> Ollama \uc124\uce58 \uc644\ub8cc (<code>irm https://ollama.com/install.ps1 | iex</code> \ub610\ub294 winget)</li> <li> \uc2dc\uc2a4\ud15c \ud2b8\ub808\uc774\uc5d0 Ollama \uc544\uc774\ucf58 \ud655\uc778</li> <li> <code>ollama pull llama3.2</code> \uc644\ub8cc</li> <li> <code>curl http://localhost:11434/api/tags</code> \u2192 \ubaa8\ub378 \ubaa9\ub85d \uc751\ub2f5</li> <li> WSL2\uc5d0\uc11c\ub3c4 \ub3d9\uc77c \uc8fc\uc18c\ub85c \uc811\uadfc \ud655\uc778</li> </ul>"},{"location":"agents/ollama_setup.html#result","title":"Result","text":"\ud56d\ubaa9 \uacb0\uacfc Windows \uc124\uce58 \ub300\uae30 \uc911 \ubaa8\ub378 \ub2e4\uc6b4\ub85c\ub4dc \ub300\uae30 \uc911 API \uc751\ub2f5 \ub300\uae30 \uc911 WSL2 \uc5f0\uacb0 \ub300\uae30 \uc911"},{"location":"agents/ollama_setup.html#notes","title":"Notes","text":"<ul> <li>(\uc2e4\ud589 \ud6c4 \uae30\ub85d)</li> </ul>"},{"location":"agents/ollama_setup.html#related","title":"Related","text":"<ul> <li>window_wsl2_setup.md \u2014 WSL2\uc5d0\uc11c OpenClaw \uc124\uce58</li> <li>../agents/ollama.md \u2014 Ollama \uc5d0\uc774\uc804\ud2b8 \uc124\uc815</li> </ul>"},{"location":"architecture/system-design.html","title":"System Design","text":"<ul> <li> <p>AI Agent \uad6c\uc870 </p> <ul> <li>Claude: \uad6c\uc870 \uc124\uacc4, \uc791\uc5c5 \ubd84\ud574, \ub9ac\ud329\ud1a0\ub9c1 \ubc29\ud5a5, \ucf54\ub4dc \uc0dd\uc131, \ubb38\uc11c\ud654</li> <li>Codex: PR \ub9ac\ubdf0, \ud68c\uadc0 \uc704\ud5d8 \uc9c0\uc801, \ud14c\uc2a4\ud2b8 \ub204\ub77d \uc9c0\uc801, \uc218\uc815 patch \ucd08\uc548</li> <li>Ollama: \ub85c\uadf8 \uc694\uc57d, \ud14c\uc2a4\ud2b8 \ucd08\uc548, \ubc18\ubcf5 \ubcc0\ud658 \uc791\uc5c5</li> <li>User: \ucd5c\uc885 \uc2b9\uc778</li> </ul> </li> <li> <p>AI Agent \uc640 Openclaw \uc5f0\uacb0 </p> <ul> <li>openclaw </li> <li>\uac01 Channel \uc5f0\uacb0  </li> <li>E-Mail \uc790\ub3d9\ubc1c\uc1a1  </li> <li>Github \ube44\ub86f\ud558\uc5ec, Slack \uacfc \uc5f0\uacb0 </li> </ul> </li> </ul> <p></p>"},{"location":"architecture/system-design.html#deployment-diagram","title":"Deployment Diagram","text":""},{"location":"architecture/system-design.html#version-a-with-openclaw","title":"Version A \u2014 With OpenClaw","text":"<p>OpenClaw\uc774 \ucc44\ub110 \ub2f4\ub2f9, MCP\ub294 <code>channels()</code> \ubbf8\uc0ac\uc6a9.</p> <pre><code>graph TD\n    subgraph UserCLI[\"Local User\"]\n        ClaudeCLI[\"Claude CLI\"]\n        CodexCLI[\"Codex CLI\"]\n        VSCode[\"VS Code \u00b7 Copilot\"]\n    end\n\n    subgraph Remote[\"Remote Cloud\"]\n        Claude[\"Claude API\"]\n        Codex[\"Codex API\"]\n    end\n\n    subgraph LocalWSL2[\"Local WSL2\"]\n        OpenClaw[\"OpenClaw\\n\ubb38\uc11c \uc0dd\uc131 \u00b7 \uacf5\uc720 \u00b7 \uc54c\ub9bc\"]\n    end\n\n    subgraph LocalWindows[\"Local Windows 11\"]\n        Ollama[\"Ollama\"]\n        subgraph MCPTools[\"MCP Tool Server\"]\n            Build[\"build_tool()\\nmake \u00b7 cmake \u00b7 bitbake\"]\n            Flash[\"flash_tool()\\nOpenOCD \u00b7 JLink \u00b7 dfu-util\"]\n            Uart[\"uart_capture()\\npyserial \u00b7 minicom\"]\n            Qemu[\"qemu_spawn()\\nQEMU instance\"]\n            LogA[\"log_analyzer()\\noops \u00b7 panic \u00b7 assert\"]\n            Reg[\"reg_dump()\\n/dev/mem \u00b7 devmem2 \u00b7 debugfs\"]\n        end\n    end\n\n    subgraph Channels[\"Remote Channels\"]\n        GitHub[\"GitHub\\nCopilot PR Review\"]\n        Slack[\"Slack AI\"]\n        EMail[\"E-Mail\"]              \n    end\n\n    ClaudeCLI --&gt; Claude\n    CodexCLI --&gt; Codex\n    VSCode --&gt;|Copilot| GitHub\n\n    Claude --&gt; OpenClaw\n    Codex --&gt; OpenClaw\n    Ollama --&gt; OpenClaw\n\n    Claude --&gt;|HTTP| MCPTools\n    Codex --&gt;|HTTP| MCPTools\n    Ollama --&gt;|HTTP| MCPTools\n\n    OpenClaw --&gt;|API| GitHub\n    OpenClaw --&gt;|API| Slack\n    OpenClaw --&gt;|API| EMail        </code></pre>"},{"location":"architecture/system-design.html#version-b-mcp-only","title":"Version B \u2014 MCP Only","text":"<p>MCP Server\uac00 Tool \ub77c\uc6b0\ud305 + \ubb38\uc11c \uc0dd\uc131\u00b7\uacf5\uc720\u00b7\uc54c\ub9bc\uae4c\uc9c0 \ub2f4\ub2f9\ud558\ub294 \ub2e8\uc21c\ud654\ub41c \uad6c\uc870.</p> <pre><code>graph TD\n    subgraph UserCLI[\"Local User\"]\n        ClaudeCLI[\"Claude CLI\"]\n        CodexCLI[\"Codex CLI\"]\n        VSCode[\"VS Code \u00b7 Copilot\"]\n    end\n\n    subgraph Remote[\"Remote Cloud\"]\n        Claude[\"Claude API\"]\n        Codex[\"Codex API\"]\n    end\n\n    subgraph LocalWindows[\"Local Windows 11\"]\n        Ollama[\"Ollama\"]\n        subgraph MCPTools[\"MCP Tool Server\"]\n            Build[\"build_tool()\\nmake \u00b7 cmake \u00b7 bitbake\"]\n            Chan[\"channels()\\nGitHub \u00b7 Slack \u00b7 E-Mail\"]\n            Flash[\"flash_tool()\\nOpenOCD \u00b7 JLink \u00b7 dfu-util\"]\n            Uart[\"uart_capture()\\npyserial \u00b7 minicom\"]\n            Qemu[\"qemu_spawn()\\nQEMU instance\"]\n            LogA[\"log_analyzer()\\noops \u00b7 panic \u00b7 assert\"]\n            Reg[\"reg_dump()\\n/dev/mem \u00b7 devmem2 \u00b7 debugfs\"]\n        end\n    end\n\n    subgraph Channels[\"Remote Channels\"]\n        GitHub[\"GitHub\\nCopilot PR Review\"]\n        Slack[\"Slack AI\"]\n        EMail[\"E-Mail\"]        \n    end\n\n    ClaudeCLI --&gt; Claude\n    CodexCLI --&gt; Codex\n    VSCode --&gt;|Copilot| GitHub\n\n    Claude --&gt;|HTTP| MCPTools\n    Codex --&gt;|HTTP| MCPTools\n    Ollama --&gt;|HTTP| MCPTools\n\n    Chan --&gt;|API| GitHub\n    Chan --&gt;|API| Slack\n    Chan --&gt;|API| EMail    </code></pre>"},{"location":"architecture/system-design.html#component-details","title":"Component Details","text":""},{"location":"architecture/system-design.html#1-user-access","title":"1. User Access","text":"<p>\ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c <code>http://127.0.0.1:18789</code> \ub85c OpenClaw Dashboard\uc5d0 \uc811\uc18d\ud569\ub2c8\ub2e4.  Prompt\ub97c \uc785\ub825\ud558\uba74 Orchestrator\uac00 \uc791\uc5c5 \uc720\ud615\uc5d0 \ub9de\ub294 Agent\ub97c \uc120\ud0dd\ud574 \ub77c\uc6b0\ud305\ud569\ub2c8\ub2e4.</p>"},{"location":"architecture/system-design.html#2-openclaw-orchestrator-wsl2","title":"2. OpenClaw Orchestrator (WSL2)","text":"<ul> <li>\uc124\uce58 \uc704\uce58: WSL2 (Ubuntu)   </li> <li>\uc5ed\ud560: Prompt\ub97c \ubc1b\uc544 \uc801\ud569\ud55c Agent \uacb0\uc815 \u2192 MCP \uc11c\ubc84\ub85c \uc804\ub2ec   </li> <li>\ud3ec\ud2b8: <code>:18789</code> (Dashboard + Gateway)   </li> <li>WSL2\uc5d0 \uc124\uce58\ud558\ub294 \uc774\uc720: \uacf5\uc2dd \uad8c\uc7a5 \ud658\uacbd, Linux \ub124\uc774\ud2f0\ube0c \uc548\uc815\uc131</li> </ul>"},{"location":"architecture/system-design.html#3-mcp-server-wsl2","title":"3. MCP Server (WSL2)","text":"<ul> <li>\uc124\uce58 \uc704\uce58: WSL2 (Ubuntu), OpenClaw\uc640 \ub3d9\uc77c \ud658\uacbd   </li> <li>\uc5ed\ud560: Agent\uac00 \ud638\ucd9c\ud558\ub294 Tool Server \u2014 Git, \ube4c\ub4dc, \ud30c\uc77c \ub4f1 \uc678\ubd80 \uc2dc\uc2a4\ud15c \uc811\uadfc \uc81c\uacf5   </li> <li>\ud3ec\ud2b8: <code>:3000</code> </li> </ul>"},{"location":"architecture/system-design.html#tool-groups","title":"Tool Groups","text":"Tool Group \ud3ec\ud568 \ub3c4\uad6c \uc811\uadfc Agent Git / GitHub git cli, GitHub API, PR \uc0dd\uc131\u00b7\uc870\ud68c Codex, Claude Build / Test Runner \ube4c\ub4dc \uc2e4\ud589, \ud14c\uc2a4\ud2b8 \uc2e4\ud589, \uacb0\uacfc \uc218\uc9d1 Codex, Ollama Logs / Files / Reports \ub85c\uadf8 \ud30c\uc77c \uc77d\uae30, \ub9ac\ud3ec\ud2b8 \uc0dd\uc131, \ubb38\uc11c \uc800\uc7a5 Ollama, Claude"},{"location":"architecture/system-design.html#agent-mcp","title":"Agent\ubcc4 MCP \uc811\uadfc \ubc94\uc704","text":"Agent \uc811\uadfc Tool Claude Git (\ucf54\ub4dc \uc77d\uae30), Logs / Files (\ubb38\uc11c \uc800\uc7a5) Codex Git / GitHub (PR \uc0dd\uc131\u00b7\ub9ac\ubdf0), Build / Test Runner (\ud68c\uadc0 \uac80\uc99d) Ollama Build / Test Runner (\ud14c\uc2a4\ud2b8 \ucd08\uc548), Logs / Files (\ub85c\uadf8 \ubd84\uc11d)"},{"location":"architecture/system-design.html#4-ollama-windows-native","title":"4. Ollama (Windows Native)","text":"<ul> <li>\uc124\uce58 \uc704\uce58: Windows 11 \ud638\uc2a4\ud2b8   </li> <li>\uc5ed\ud560: \ub85c\uceec LLM \ucd94\ub860, \uc778\ud130\ub137 \uc5c6\uc774 \ub3d9\uc791   </li> <li>\ud3ec\ud2b8: <code>:11434</code> </li> <li>\ubaa8\ub378: <code>llama3.2</code> (\ubc94\uc6a9), <code>codellama</code> (\ucf54\ub4dc \ud2b9\ud654)   </li> <li>Windows\uc5d0 \uc124\uce58\ud558\ub294 \uc774\uc720: GPU \uc9c1\uc811 \uc811\uadfc\uc73c\ub85c \ucd94\ub860 \uc131\ub2a5 \ucd5c\uc801\ud654   </li> <li>WSL2 \u2192 Windows \uc5f0\uacb0: <code>localhost:11434</code> \ub85c \ud22c\uba85\ud558\uac8c \uc811\uadfc \uac00\ub2a5</li> </ul>"},{"location":"architecture/system-design.html#5-claude-api-cloud","title":"5. Claude API (Cloud)","text":"<ul> <li>\uc124\uce58 \uc704\uce58: \uc5c6\uc74c \u2014 Anthropic \ud074\ub77c\uc6b0\ub4dc\uc5d0\uc11c \uc2e4\ud589   </li> <li>\uc5f0\uacb0 \ubc29\uc2dd: <code>ANTHROPIC_API_KEY</code> \ud658\uacbd\ubcc0\uc218   </li> <li>\uc6a9\ub3c4: \ucd94\ub860, \ubd84\uc11d, \uc7a5\ubb38 \ucee8\ud14d\uc2a4\ud2b8 \ucc98\ub9ac</li> </ul>"},{"location":"architecture/system-design.html#6-codex-api-cloud","title":"6. Codex API (Cloud)","text":"<ul> <li>\uc124\uce58 \uc704\uce58: \uc5c6\uc74c \u2014 OpenAI \ud074\ub77c\uc6b0\ub4dc\uc5d0\uc11c \uc2e4\ud589   </li> <li>\uc5f0\uacb0 \ubc29\uc2dd: <code>OPENAI_API_KEY</code> \ud658\uacbd\ubcc0\uc218   </li> <li>\uc6a9\ub3c4: \ucf54\ub4dc \uc0dd\uc131, \ub9ac\ud329\ud1a0\ub9c1, \uc5b8\uc5b4 \ubcc0\ud658</li> </ul>"},{"location":"architecture/system-design.html#installation-locations","title":"Installation Locations","text":"\ucef4\ud3ec\ub10c\ud2b8 \uc124\uce58 \uc704\uce58 \ud3ec\ud2b8 OpenClaw WSL2 (Ubuntu) :18789 MCP Server WSL2 (Ubuntu) :3000 Node.js 24 WSL2 (Ubuntu) \u2014 Ollama Windows 11 (\ud638\uc2a4\ud2b8) :11434 Claude API \ud074\ub77c\uc6b0\ub4dc \u2014 Codex API \ud074\ub77c\uc6b0\ub4dc \u2014"},{"location":"architecture/system-design.html#agent-workflow","title":"Agent Workflow","text":"<p>Agent \uc5ed\ud560\uc740 \uace0\uc815, \uc544\ub798 \uc21c\uc11c\ub85c \uc2e4\ud589.</p>"},{"location":"architecture/system-design.html#ai-agent-harness-version-a","title":"AI Agent Harness Version A","text":"<p>OpenClaw\uac00 \ubb38\uc11c \uc0dd\uc131\u00b7\uacf5\uc720\u00b7\uc54c\ub9bc\uc744 \ub2f4\ub2f9\ud558\ub294 \uad6c\uc870.</p> \uc21c\uc11c \uc791\uc5c5 \uc720\ud615 Agent Orchestrator User \uac80\ud1a0 1 \uad6c\uc870 \uc124\uacc4 / \uc791\uc5c5 \ubd84\ud574 / \ub9ac\ud329\ud1a0\ub9c1 \ubc29\ud5a5 Claude OpenClaw \u2014 2 \ucf54\ub4dc \uc0dd\uc131 Claude OpenClaw 1\ucc28 \uc2b9\uc778 / \uc218\uc815 3 \ubb38\uc11c\ud654 Claude OpenClaw 2\ucc28 \uc2b9\uc778 / \uc218\uc815 4 \ud68c\uadc0 \uc704\ud5d8 \uc9c0\uc801 / \ud14c\uc2a4\ud2b8 \ub204\ub77d \uc9c0\uc801 / patch \ucd08\uc548 Codex OpenClaw 3\ucc28 \uc2b9\uc778 / \uc218\uc815 5 GitHub PR \uc694\uccad GitHub OpenClaw \u2014 6 PR Review Codex + GitHub Users OpenClaw 4\ucc28 \uc2b9\uc778 / \uc218\uc815 7 \ub85c\uadf8 \uc694\uc57d / \ud14c\uc2a4\ud2b8 \ucd08\uc548 / \ubc18\ubcf5 \ubcc0\ud658 \uc791\uc5c5 Ollama OpenClaw 5\ucc28 \uc2b9\uc778 / \uc218\uc815 8 \uacb0\uacfc \ud14c\uc2a4\ud2b8 \ubb38\uc11c\ud654 Codex OpenClaw 6\ucc28 \uc2b9\uc778 / \uc218\uc815"},{"location":"architecture/system-design.html#ai-agent-harness-version-b","title":"AI Agent Harness Version B","text":"<p>MCP Server\uac00 Orchestrator \uc5ed\ud560\uae4c\uc9c0 \ub2f4\ub2f9\ud558\ub294 \ub2e8\uc21c\ud654\ub41c \uad6c\uc870.</p> \uc21c\uc11c \uc791\uc5c5 \uc720\ud615 Agent Orchestrator User \uac80\ud1a0 1 \uad6c\uc870 \uc124\uacc4 / \uc791\uc5c5 \ubd84\ud574 / \ub9ac\ud329\ud1a0\ub9c1 \ubc29\ud5a5 Claude MCP \u2014 2 \ucf54\ub4dc \uc0dd\uc131 Claude MCP 1\ucc28 \uc2b9\uc778 / \uc218\uc815 3 \ubb38\uc11c\ud654 Claude MCP 2\ucc28 \uc2b9\uc778 / \uc218\uc815 4 \ud68c\uadc0 \uc704\ud5d8 \uc9c0\uc801 / \ud14c\uc2a4\ud2b8 \ub204\ub77d \uc9c0\uc801 / patch \ucd08\uc548 Codex MCP 3\ucc28 \uc2b9\uc778 / \uc218\uc815 5 GitHub PR \uc694\uccad GitHub MCP \u2014 6 PR Review Codex + GitHub Users MCP 4\ucc28 \uc2b9\uc778 / \uc218\uc815 7 \ub85c\uadf8 \uc694\uc57d / \ud14c\uc2a4\ud2b8 \ucd08\uc548 / \ubc18\ubcf5 \ubcc0\ud658 \uc791\uc5c5 Ollama MCP 5\ucc28 \uc2b9\uc778 / \uc218\uc815 8 \uacb0\uacfc \ud14c\uc2a4\ud2b8 \ubb38\uc11c\ud654 Codex MCP 6\ucc28 \uc2b9\uc778 / \uc218\uc815"},{"location":"architecture/system-design.html#related","title":"Related","text":"<ul> <li>agents/claude.md \u2014 Claude Agent \uc124\uc815</li> <li>agents/ollama.md \u2014 Ollama Agent \uc124\uc815</li> <li>agents/codex.md \u2014 Codex Agent \uc124\uc815</li> <li>mcp/mcp_server.md \u2014 MCP \uc11c\ubc84 \uc124\uc815</li> <li>environments/window_wsl2_setup.md \u2014 WSL2 \uc124\uce58 \uc2e4\ud5d8</li> <li>agents/ollama_setup.md \u2014 Ollama \uc124\uce58 \uc2e4\ud5d8</li> </ul>"},{"location":"environments/window_wsl2_setup.html","title":"Experiment: OpenClaw Setup on WSL2","text":""},{"location":"environments/window_wsl2_setup.html#goal","title":"Goal","text":"<p>Windows 11 + WSL2(Ubuntu) \ud658\uacbd\uc5d0\uc11c OpenClaw\ub97c \uc124\uce58\ud558\uace0 \ub3d9\uc791\uc744 \uac80\uc99d\ud569\ub2c8\ub2e4.</p>"},{"location":"environments/window_wsl2_setup.html#environment","title":"Environment","text":"\ud56d\ubaa9 \uac12 OS Windows 11 Pro WSL \ubc84\uc804 WSL2 \ubc30\ud3ec\ud310 Ubuntu \uad8c\uc7a5 \uc774\uc720 Windows \ub124\uc774\ud2f0\ube0c\ubcf4\ub2e4 \uc548\uc815\uc801 (\uacf5\uc2dd \ubb38\uc11c \uad8c\uc7a5)"},{"location":"environments/window_wsl2_setup.html#setup-steps","title":"Setup Steps","text":""},{"location":"environments/window_wsl2_setup.html#step-1-enter-wsl2-ubuntu","title":"Step 1: Enter WSL2 Ubuntu","text":"<p>Windows PowerShell: <pre><code>wsl -d Ubuntu\n</code></pre></p>"},{"location":"environments/window_wsl2_setup.html#step-2-install-nodejs-24","title":"Step 2: Install Node.js 24","text":"<pre><code>curl -fsSL https://fnm.vercel.app/install | bash\nsource ~/.bashrc\n\nfnm install 24\nfnm use 24\nnode -v   # v24.x.x \ud655\uc778\nnpm -v\n</code></pre> <p>fnm\uc744 \uc4f0\ub294 \uc774\uc720: WSL2\uc5d0\uc11c nvm\ubcf4\ub2e4 \ube60\ub974\uace0, <code>.node-version</code> \ud30c\uc77c\ub85c \ud504\ub85c\uc81d\ud2b8\ubcc4 \ubc84\uc804 \uace0\uc815 \uac00\ub2a5</p>"},{"location":"environments/window_wsl2_setup.html#step-3-install-openclaw","title":"Step 3: Install OpenClaw","text":"<pre><code>curl -fsSL https://openclaw.ai/install.sh | bash\n</code></pre>"},{"location":"environments/window_wsl2_setup.html#step-4-authenticate-claude-cli","title":"Step 4: Authenticate Claude CLI","text":"<p>OpenClaw\uc5d0\uc11c Claude CLI\ub97c \uc0ac\uc6a9\ud558\ub294 \uacbd\uc6b0 \uc778\uc99d\uc774 \ud544\uc694\ud569\ub2c8\ub2e4. \uc790\uc138\ud55c \uc778\uc99d \ubc29\ubc95\uc740 docs/agents/claude_setup.md - Authentication\uc744 \ucc38\uace0\ud558\uc138\uc694.</p> <p>Option A: Windows Credentials \ubcf5\uc0ac (Claude Code \uae30\uc874 \uc0ac\uc6a9\uc790)</p> <p>Windows\uc5d0\uc11c \uc774\ubbf8 <code>claude auth login</code>\uc744 \uc644\ub8cc\ud55c \uacbd\uc6b0 credentials \ud30c\uc77c\uc744 \ubcf5\uc0ac\ud569\ub2c8\ub2e4.</p> <pre><code># WSL2 \ub0b4\uc5d0\uc11c \uc2e4\ud589\ncp /mnt/c/Users/ahyuo/.claude/.credentials ~/.claude/.credentials\n</code></pre> <p>Option B: API Key \ud658\uacbd\ubcc0\uc218</p> <pre><code>echo 'export ANTHROPIC_API_KEY=\"sk-ant-...\"' &gt;&gt; ~/.bashrc\nsource ~/.bashrc\n</code></pre>"},{"location":"environments/window_wsl2_setup.html#step-5-onboarding-model-provider-api-key","title":"Step 5: Onboarding (Model Provider + API Key)","text":"<ul> <li> <p>General  <pre><code>openclaw onboard --install-daemon \n</code></pre></p> </li> <li> <p>Skip-Channel  \uc0c1\uc704\uc5d0\uc11c skip channel\ud558\uba74 \uc5d0\ub7ec\uac00 \ubc1c\uc0dd\ud574\uc11c Command \uc0dd\ub7b5 <pre><code>openclaw onboard --install-daemon --skip-channels\n</code></pre></p> </li> <li> <p>\uc124\uc815 \ud6c4 \ub3d9\uc791  \ubc18\ub4dc\uc2dc Token \uae30\ubc18\uc73c\ub85c Web\uc5d0\uc11c \uc811\uc18d  <pre><code>\u2502\n\u25c7  I understand this is personal-by-default and shared/multi-user use requires lock-down.\n\u2502   Continue?\n\u2502  Yes\n\u2502\n\u25c7  Setup mode\n\u2502  QuickStart\n\u2502\n\u25c7  QuickStart \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                                      \u2502\n\u2502  Gateway port: 18789                 \u2502\n\u2502  Gateway bind: Loopback (127.0.0.1)  \u2502\n\u2502  Gateway auth: Token (default)       \u2502\n\u2502  Tailscale exposure: Off             \u2502\n\u2502  Direct to chat channels.            \u2502\n\u2502                                      \u2502\n\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256f\n\u2502\n\u25c7  Model/auth provider\n\u2502  Anthropic\n\u2502\n\u25c7  Anthropic auth method\n\u2502  Anthropic Claude CLI\n\u2502\n\u25c7  Provider notes \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                                                                                        \u2502\n\u2502  Claude CLI auth detected; switched Anthropic model selection to the local Claude CLI  \u2502\n\u2502  backend.                                                                              \u2502\n\u2502  Existing Anthropic auth profiles are kept for rollback.                               \u2502\n\u2502                                                                                        \u2502\n\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256f\n\u2502\n\u25c7  Model configured \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                                                     \u2502\n\u2502  Default model set to claude-cli/claude-sonnet-4-6  \u2502\n\u2502                                                     \u2502\n\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256f\n\u2502\n\u25c7  Default model\n\u2502  Keep current (claude-cli/claude-sonnet-4-6)\n\u2502\n\u25c7  Model check \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                                                                                      \u2502\n\u2502  Model not found: claude-cli/claude-sonnet-4-6. Update agents.defaults.model or run  \u2502\n\u2502  /models list.                                                                       \u2502\n\u2502                                                                                      \u2502\n\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256f\n\u2502\n\u25c7  Channels \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                           \u2502\n\u2502  Skipping channel setup.  \u2502\n\u2502                           \u2502\n\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256f\nUpdated ~/.openclaw/openclaw.json\nWorkspace OK: ~/.openclaw/workspace\nSessions OK: ~/.openclaw/agents/main/sessions\n\u2502\n\u25c7  Web search \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                                                                              \u2502\n\u2502  Web search lets your agent look things up online.                           \u2502\n\u2502  Choose a provider. Some providers need an API key, and some work key-free.  \u2502\n\u2502  Docs: https://docs.openclaw.ai/tools/web                                    \u2502\n\u2502                                                                              \u2502\n\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256f\n\u2502\n\u25c7  Search provider\n\u2502  Ollama Web Search\n\u2502\n\u25c7  Web search \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                                                                           \u2502\n\u2502  Ollama Web Search works without an API key.                              \u2502\n\u2502  OpenClaw will enable the plugin and use it as your web_search provider.  \u2502\n\u2502  Docs: https://docs.openclaw.ai/tools/web                                 \u2502\n\u2502                                                                           \u2502\n\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256f\n\u2502\n\u25c7  Ollama Web Search \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                                                    \u2502\n\u2502  Ollama Web Search requires Ollama to be running.  \u2502\n\u2502  Expected host: http://127.0.0.1:11434             \u2502\n\u2502  Start Ollama before using this provider.          \u2502\n\u2502                                                    \u2502\n\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256f\n\u2502\n\u25c7  Skills status \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                             \u2502\n\u2502  Eligible: 8                \u2502\n\u2502  Missing requirements: 37   \u2502\n\u2502  Unsupported on this OS: 7  \u2502\n\u2502  Blocked by allowlist: 0    \u2502\n\u2502                             \u2502\n\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256f\n\u2502\n\u25c7  Configure skills now? (recommended)\n\u2502  Yes\n\u2502\n\u25c7  Install missing skill dependencies\n\u2502  Skip for now\n\u2502\n\u25c7  Set GOOGLE_PLACES_API_KEY for goplaces?\n\u2502  No\n\u2502\n\u25c7  Set NOTION_API_KEY for notion?\n\u2502  No\n\u2502\n\u25c7  Set OPENAI_API_KEY for openai-whisper-api?\n\u2502  No\n\u2502\n\u25c7  Set ELEVENLABS_API_KEY for sag?\n\u2502  No\n\u2502\n\u25c7  Hooks \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                                                                          \u2502\n\u2502  Hooks let you automate actions when agent commands are issued.          \u2502\n\u2502  Example: Save session context to memory when you issue /new or /reset.  \u2502\n\u2502                                                                          \u2502\n\u2502  Learn more: https://docs.openclaw.ai/automation/hooks                   \u2502\n\u2502                                                                          \u2502\n\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256f\n\u2502\n\u25c7  Enable hooks?\n\u2502  Skip for now\n\u2502\n\u25c7  Systemd \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                                                                                          \u2502\n\u2502  Linux installs use a systemd user service by default. Without lingering, systemd stops  \u2502       \n\u2502  the user session on logout/idle and kills the Gateway.                                  \u2502       \n\u2502  Enabling lingering now (may require sudo; writes /var/lib/systemd/linger).              \u2502       \n\u2502                                                                                          \u2502       \n\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256f       \n\u2502\n\u25c7  Systemd \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                                        \u2502\n\u2502  Enabled systemd lingering for ahyuo.  \u2502\n\u2502                                        \u2502\n\u251c\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256f\n\u2502\n\u25c7  Gateway service runtime \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u256e\n\u2502                                                                      \u2502\n\u2502  QuickStart uses Node for the Gateway service (stable + supported).  \u2502\n\u2502                                                                      \u2502\n....           \n\nopenclaw tui - ws://127.0.0.1:18789 - agent main - session main\n\n session agent:main:main\n\n\nWake up, my friend!\n\n\n \u2807 kerfuffling\u2026 \u2022 14m 58s | connected                                                                                                                                    \n agent main | session main | unknown | tokens ?/200k\n</code></pre></p> </li> <li> <p>Model Provider \uc120\ud0dd: Anthropic / OpenAI / Google</p> </li> <li>API \ud0a4 \uc785\ub825</li> <li>Gateway \uc790\ub3d9 \uc124\uc815 (~2\ubd84 \uc18c\uc694)</li> </ul>"},{"location":"environments/window_wsl2_setup.html#step-6-verify-gateway","title":"Step 6: Verify Gateway","text":"<pre><code># Gateway \ud1a0\ud070 \ud655\uc778\nopenclaw config get gateway.token\n\n# \ud1a0\ud070\uacfc \ud568\uaed8 \uc0c1\ud0dc \ud655\uc778\nopenclaw gateway status --token &lt;\uc704\uc5d0\uc11c \ud655\uc778\ud55c \ud1a0\ud070&gt;\n</code></pre> <p><code>unauthorized: gateway token missing</code> \uc624\ub958 \ubc1c\uc0dd \uc2dc \uc704 \uc21c\uc11c\ub85c \ud1a0\ud070\uc744 \uba3c\uc800 \ud655\uc778\ud55c\ub2e4.</p>"},{"location":"environments/window_wsl2_setup.html#step-7-open-dashboard","title":"Step 7: Open Dashboard","text":"<pre><code>openclaw dashboard\n</code></pre> <p>WSL2\uc5d0\uc11c \uc2e4\ud589\ud574\ub3c4 Windows \ube0c\ub77c\uc6b0\uc800\uc5d0\uc11c <code>http://127.0.0.1:18789/</code> \ub85c \uc811\uc18d \uac00\ub2a5\ud569\ub2c8\ub2e4.</p>"},{"location":"environments/window_wsl2_setup.html#checklist","title":"Checklist","text":"<ul> <li>[O] WSL2 Ubuntu \uc9c4\uc785 \ud655\uc778</li> <li>[O] Node.js 24 \uc124\uce58 \uc644\ub8cc</li> <li>[O] OpenClaw \uc124\uce58 \uc644\ub8cc</li> <li> Claude CLI \uc778\uc99d \uc644\ub8cc (Option A \ub610\ub294 B)</li> <li> <code>openclaw onboard</code> \uc644\ub8cc (API \ud0a4 \uc124\uc815)</li> <li> <code>openclaw gateway status</code> \u2192 \uc815\uc0c1 \uc751\ub2f5</li> <li> \ub300\uc2dc\ubcf4\ub4dc \ube0c\ub77c\uc6b0\uc800 \uc811\uc18d \ud655\uc778</li> </ul>"},{"location":"environments/window_wsl2_setup.html#result","title":"Result","text":"\ud56d\ubaa9 \uacb0\uacfc \uc124\uce58 \ub300\uae30 \uc911 Gateway \uae30\ub3d9 \ub300\uae30 \uc911 \ub300\uc2dc\ubcf4\ub4dc \uc811\uc18d \ub300\uae30 \uc911"},{"location":"environments/window_wsl2_setup.html#notes","title":"Notes","text":"<ul> <li>Step 5: \ucc44\ub110\uc774 \uc5c6\ub294 \uacbd\uc6b0 <code>--skip-channels</code> \uc635\uc158\uc73c\ub85c \ucc44\ub110 \uc124\uc815\uc744 \uac74\ub108\ub700. \"Skip for now\" UI \uc120\ud0dd \uc2dc <code>TypeError: Cannot read properties of undefined (reading 'trim')</code> \ubc84\uadf8 \ubc1c\uc0dd\ud558\ubbc0\ub85c \ubc18\ub4dc\uc2dc CLI \uc635\uc158\uc73c\ub85c \ucc98\ub9ac.</li> <li>Step 6: <code>openclaw gateway status</code> \uc2e4\ud589 \uc2dc <code>unauthorized: gateway token missing</code> \uc624\ub958 \ubc1c\uc0dd \uac00\ub2a5. <code>openclaw config get gateway.token</code>\uc73c\ub85c \ud1a0\ud070 \ud655\uc778 \ud6c4 <code>--token</code> \uc635\uc158\uc73c\ub85c \uc804\ub2ec \ud544\uc694.</li> </ul>"},{"location":"experiments/openclaw_test.html","title":"Experiment: OpenClaw Initial Test","text":""},{"location":"experiments/openclaw_test.html#goal","title":"Goal","text":"<p>Orchestrator\uac00 \uac01 Agent\ub85c Prompt\ub97c \ub77c\uc6b0\ud305\ud558\uace0 MCP\ub97c \ud1b5\ud574 \uc720\ud6a8\ud55c \uc751\ub2f5\uc744 \ubc1b\ub294\uc9c0 \uac80\uc99d\ud569\ub2c8\ub2e4.</p>"},{"location":"experiments/openclaw_test.html#test-cases","title":"Test Cases","text":""},{"location":"experiments/openclaw_test.html#1-code-generation-codex","title":"1. Code Generation \u2192 Codex","text":"<p>\uc785\ub825: <pre><code>Write a Python function that reads a CSV file and returns a list of dicts.\n</code></pre></p> <p>\uc608\uc0c1 Agent: Codex \uc608\uc0c1 \ucd9c\ub825: \uc62c\ubc14\ub978 CSV \ud30c\uc2f1 \ub85c\uc9c1\uc774 \ud3ec\ud568\ub41c Python \ud568\uc218</p> <p>\uacb0\uacfc: [ ] Pass / [ ] Fail \uba54\ubaa8:</p>"},{"location":"experiments/openclaw_test.html#2-reasoning-explanation-claude","title":"2. Reasoning / Explanation \u2192 Claude","text":"<p>\uc785\ub825: <pre><code>Explain the trade-offs between REST and GraphQL for a mobile app backend.\n</code></pre></p> <p>\uc608\uc0c1 Agent: Claude \uc608\uc0c1 \ucd9c\ub825: \uba85\ud655\ud55c \ud2b8\ub808\uc774\ub4dc\uc624\ud504\uac00 \ub2f4\uae34 \uad6c\uc870\ud654\ub41c \ube44\uad50</p> <p>\uacb0\uacfc: [ ] Pass / [ ] Fail \uba54\ubaa8:</p>"},{"location":"experiments/openclaw_test.html#3-local-inference-ollama","title":"3. Local Inference \u2192 Ollama","text":"<p>\uc785\ub825: <pre><code>Summarize the following paragraph in one sentence: [paragraph]\n</code></pre></p> <p>\uc608\uc0c1 Agent: Ollama (<code>llama3.2</code>) \uc608\uc0c1 \ucd9c\ub825: \ud55c \ubb38\uc7a5 \uc694\uc57d</p> <p>\uacb0\uacfc: [ ] Pass / [ ] Fail \uba54\ubaa8:</p>"},{"location":"experiments/openclaw_test.html#4-agent-handoff-codex-claude","title":"4. Agent Handoff (Codex \u2192 Claude)","text":"<p>\uc785\ub825: <pre><code>Generate a sorting function, then explain how it works.\n</code></pre></p> <p>\uc608\uc0c1 \ud750\ub984: Codex\uac00 \ucf54\ub4dc \uc0dd\uc131 \u2192 Claude\uac00 \uc124\uba85 \uc608\uc0c1 \ucd9c\ub825: \ucf54\ub4dc \ube14\ub85d + \uc124\uba85</p> <p>\uacb0\uacfc: [ ] Pass / [ ] Fail \uba54\ubaa8:</p>"},{"location":"experiments/openclaw_test.html#how-to-run","title":"How to Run","text":"<p>Windows <pre><code># MCP \uc11c\ubc84 \uc2dc\uc791\nnode mcp-server.js\n\n# \ud14c\uc2a4\ud2b8 \uc2e4\ud589\nnode run-experiments.js --suite openclaw-test\n</code></pre></p> <p>Linux / macOS <pre><code># MCP \uc11c\ubc84 \uc2dc\uc791\nnode mcp-server.js\n\n# \ud14c\uc2a4\ud2b8 \uc2e4\ud589\nnode run-experiments.js --suite openclaw-test\n</code></pre></p>"},{"location":"experiments/openclaw_test.html#success-criteria","title":"Success Criteria","text":"<ul> <li>4\uac1c \ud14c\uc2a4\ud2b8 \ucf00\uc774\uc2a4 \ubaa8\ub450 \uc62c\ubc14\ub978 Agent\ub85c \ub77c\uc6b0\ud305</li> <li>MCP \uc804\uc1a1 \uc624\ub958 \uc5c6\uc74c</li> <li><code>logs/run_001.md</code>\uc5d0 \ub85c\uadf8 \uae30\ub85d \uc644\ub8cc</li> </ul>"},{"location":"logs/run_001.html","title":"Run Log: run-001","text":""},{"location":"logs/run_001.html#metadata","title":"Metadata","text":"\ud56d\ubaa9 \uac12 \ub0a0\uc9dc 2026-04-15 \uc2e4\ud5d8 openclaw_test MCP \uc11c\ubc84 localhost:3000 \uc2e4\ud589 \ud658\uacbd Windows 11 \uc0c1\ud0dc \ub300\uae30 \uc911"},{"location":"logs/run_001.html#runs","title":"Runs","text":""},{"location":"logs/run_001.html#run-1-codex-code-generation","title":"Run 1 \u2014 Codex: Code Generation","text":"\ud56d\ubaa9 \uac12 Agent codex \ubaa8\ub378 gpt-4o \uc9c0\uc5f0 \uc2dc\uac04 \u2014 ms Tokens Used \u2014 \uc0c1\ud0dc \ub300\uae30 \uc911 <p>Prompt: <pre><code>Write a Python function that reads a CSV file and returns a list of dicts.\n</code></pre></p> <p>\ucd9c\ub825: <pre><code>(\ubbf8\uc2e4\ud589)\n</code></pre></p>"},{"location":"logs/run_001.html#run-2-claude-reasoning","title":"Run 2 \u2014 Claude: Reasoning","text":"\ud56d\ubaa9 \uac12 Agent claude \ubaa8\ub378 claude-sonnet-4-6 \uc9c0\uc5f0 \uc2dc\uac04 \u2014 ms Tokens Used \u2014 \uc0c1\ud0dc \ub300\uae30 \uc911 <p>Prompt: <pre><code>Explain the trade-offs between REST and GraphQL for a mobile app backend.\n</code></pre></p> <p>\ucd9c\ub825: <pre><code>(\ubbf8\uc2e4\ud589)\n</code></pre></p>"},{"location":"logs/run_001.html#run-3-ollama-local-inference","title":"Run 3 \u2014 Ollama: Local Inference","text":"\ud56d\ubaa9 \uac12 Agent ollama \ubaa8\ub378 llama3.2 \uc9c0\uc5f0 \uc2dc\uac04 \u2014 ms Tokens Used \u2014 \uc0c1\ud0dc \ub300\uae30 \uc911 <p>Prompt: <pre><code>Summarize the following paragraph in one sentence: [paragraph]\n</code></pre></p> <p>\ucd9c\ub825: <pre><code>(\ubbf8\uc2e4\ud589)\n</code></pre></p>"},{"location":"logs/run_001.html#summary","title":"Summary","text":"\ud14c\uc2a4\ud2b8 \ucf00\uc774\uc2a4 Agent \uacb0\uacfc \ucf54\ub4dc \uc0dd\uc131 Codex \ub300\uae30 \uc911 \ucd94\ub860 Claude \ub300\uae30 \uc911 \ub85c\uceec \ucd94\ub860 Ollama \ub300\uae30 \uc911 Agent \uc778\uacc4 Codex\u2192Claude \ub300\uae30 \uc911"},{"location":"logs/run_001.html#observations","title":"Observations","text":"<ul> <li>(\uc2e4\ud589 \ud6c4 \uae30\ub85d)</li> </ul>"},{"location":"logs/run_001.html#next-steps","title":"Next Steps","text":"<ul> <li>(\uc2e4\ud589 \ud6c4 \uae30\ub85d)</li> </ul>"},{"location":"mcp/mcp_server.html","title":"MCP Server","text":""},{"location":"mcp/mcp_server.html#overview","title":"Overview","text":"<p>MCP(Model Context Protocol) \uc11c\ubc84\ub294 Orchestrator\uc640 AI Agent \uc0ac\uc774\uc758 \uc804\uc1a1 \ub808\uc774\uc5b4 \uc5ed\ud560\uc744 \ud569\ub2c8\ub2e4.  \uac01 Agent\ub294 Orchestrator\uac00 \ud638\ucd9c\ud560 \uc218 \uc788\ub294 Tool\ub85c \ub4f1\ub85d\ub429\ub2c8\ub2e4.</p>"},{"location":"mcp/mcp_server.html#server-setup","title":"Server Setup","text":"<p>Windows / Linux \uacf5\ud1b5 <pre><code># MCP SDK \uc124\uce58\nnpm install @modelcontextprotocol/sdk\n\n# \uc11c\ubc84 \uc2dc\uc791\nnode mcp-server.js\n</code></pre></p>"},{"location":"mcp/mcp_server.html#registered-tools","title":"Registered Tools","text":"Tool \uc774\ub984 Agent \uc124\uba85 <code>codex.run</code> Codex \ucf54\ub4dc \uc0dd\uc131 Prompt \uc2e4\ud589 <code>claude.run</code> Claude \ucd94\ub860/\ud14d\uc2a4\ud2b8 Prompt \uc2e4\ud589 <code>ollama.run</code> Ollama \ub85c\uceec \ucd94\ub860 Prompt \uc2e4\ud589 <code>log.write</code> System \uad6c\uc870\ud654\ub41c \uc2e4\ud589 \ub85c\uadf8 \ud56d\ubaa9 \uc791\uc131"},{"location":"mcp/mcp_server.html#tool-definition-example","title":"Tool Definition Example","text":"<pre><code>{\n  \"name\": \"claude.run\",\n  \"description\": \"Claude\uc5d0 Prompt\ub97c \ubcf4\ub0b4\uace0 \uc751\ub2f5\uc744 \ubc18\ud658\ud569\ub2c8\ub2e4.\",\n  \"inputSchema\": {\n    \"type\": \"object\",\n    \"properties\": {\n      \"prompt\": { \"type\": \"string\" },\n      \"context\": { \"type\": \"string\" },\n      \"model\": { \"type\": \"string\", \"default\": \"claude-sonnet-4-6\" }\n    },\n    \"required\": [\"prompt\"]\n  }\n}\n</code></pre>"},{"location":"mcp/mcp_server.html#server-configuration-mcp-configjson","title":"Server Configuration (<code>mcp-config.json</code>)","text":"<pre><code>{\n  \"server\": {\n    \"name\": \"openclaw-mcp\",\n    \"version\": \"0.1.0\",\n    \"port\": 3000\n  },\n  \"agents\": {\n    \"claude\": { \"enabled\": true },\n    \"codex\": { \"enabled\": true },\n    \"ollama\": { \"enabled\": true, \"base_url\": \"http://localhost:11434\" }\n  },\n  \"logging\": {\n    \"output_dir\": \"../logs\",\n    \"format\": \"markdown\"\n  }\n}\n</code></pre>"},{"location":"mcp/mcp_server.html#protocol-flow","title":"Protocol Flow","text":"<pre><code>sequenceDiagram\n    participant O as Orchestrator\n    participant M as MCP Server\n    participant A as Agent (Claude / Codex / Ollama)\n\n    O-&gt;&gt;M: POST /mcp/tool/call { name, args }\n    M-&gt;&gt;A: Tool \ud638\ucd9c (HTTP / local)\n    A--&gt;&gt;M: \uc751\ub2f5 \ubc18\ud658\n    M--&gt;&gt;O: { result, tokens_used, latency_ms }</code></pre> \ud544\ub4dc \uc124\uba85 <code>name</code> Tool \uc774\ub984 (\uc608: <code>claude.run</code>) <code>args</code> Tool \uc778\uc790 (\uc608: <code>{ prompt: \"...\" }</code>) <code>result</code> Agent \uc751\ub2f5 \ud14d\uc2a4\ud2b8 <code>tokens_used</code> \uc18c\ube44\ub41c Token \uc218 <code>latency_ms</code> \uc751\ub2f5 \uc9c0\uc5f0 \uc2dc\uac04 (ms)"},{"location":"mcp/mcp_server.html#notes","title":"Notes","text":"<ul> <li>\uae30\ubcf8\uc801\uc73c\ub85c <code>localhost:3000</code>\uc5d0\uc11c \uc2e4\ud589</li> <li><code>logging.format</code> \uc124\uc815 \uc2dc \ubaa8\ub4e0 Tool \ud638\ucd9c \uc790\ub3d9 \ub85c\uae45</li> <li>\uc0c8 Agent \ucd94\uac00: \uc0c8 Tool \uc815\uc758\uc640 Adapter \ub4f1\ub85d\uc73c\ub85c \ud655\uc7a5 \uac00\ub2a5</li> </ul>"}]}